INSERT INTO public.homepage_hero_settings (id, badge_text, heading_main, heading_highlight, subtitle, description, books_count_number, books_count_label, forthcoming_label, forthcoming_title, created_at, updated_at) VALUES ('1676a6fd-c912-4399-be42-22df7ffa4e94', 'Authority on Families * Author * Behavior Change Consultant* Human Development Professor  ', 'I am a Life Systems ', 'Expert', 'Specializing in psychological analysis, human development, and anti-racist frameworks', 'I am a leading authority on the lasting effects of chattel slavery on poverty and the contemporary structure of the Black family. I bring deep historical insight and interdisciplinary expertise to my work as a behavioral analyst and family expert for the Public Defender’s Office of the New Jersey Family Court, a professor, and a multiculturalism scholar. A dedicated researcher on racism and systemic inequity, My work focuses on how structural barriers—including the lack of social capital, institutional bias, and uneven resource allocation—impact both people of color and the marginalized. My scholarship illuminates how these inequities limit opportunity, influence academic pathways, contribute to long-term disparities across disciplines, and SES for generations.', '4', 'Published Textbooks', 'Watch Out For My Forthcoming Self Help Book For Adults Raised in State Care', 'So You''re on Your Own', '2026-04-21T16:25:57.234267+00:00', '2026-07-16T23:26:33.619499+00:00') ON CONFLICT DO NOTHING;

-- Data for homepage_about_settings (1 rows)
INSERT INTO public.homepage_about_settings (id, eyebrow, heading_line1, heading_highlight, paragraph1, paragraph2, quote, stat1_number, stat1_label, stat2_number, stat2_label, stat3_number, stat3_label, button_text, badge_number, badge_label, created_at, updated_at) VALUES ('b6564a4f-524b-4836-9f4c-c690c158bccd', 'More About Dr. Dina Lundy', '', '', 'Born and raised in New York City, Dr. Dina Lundy built a coffee bar chain from the ground up, becoming a millionaire at 28. That success led her to pursue something deeper—her purpose. She earned a doctorate, transitioned into academe, writing, and life coaching, helping others break through their fear and build lives they believe in and are proud of.', 'As a writer, researcher, and public speaker, her work intersects systemic inequity, implicit bias, and the phenomenology of youth whose lives have been shaped by foster care and criminal justice involvement. Her philosophy:', 'Empowerment Through Education ', '4+', 'Published Books', '100+', 'Speaking Events', '20+', 'Years Experience', 'Learn More About Dr. Lundy', '25+', 'Years of Expertise', '2026-04-28T06:57:08.742222+00:00', '2026-05-08T21:32:09.791603+00:00') ON CONFLICT DO NOTHING;

