-- Data for books (5 rows)
INSERT INTO public.books (id, title, description, price, image_url, category, is_published, created_at, updated_at, book_format, file_url) VALUES ('27863201-acdb-466f-bf82-de7f502d72ec', 'The The Psychological Perspectives of LATINX and CHICANO Populations (First Edition)!', 'The Psychological Perspectives of Latinx and Chicano Populations explores the complex dimensions of identity, growth, and the societal roles of Latinx and Chicano communities in the United States. Drawing from historical contexts and current sociopolitical landscapes, the interactive ebook examines the multifaceted issues faced by these populations, ranging from migration and population growth to acculturation and the development of ethnic identity among youth.

This interactive ebook format allows students to read the text of each chapter and engage with digital learning activities—including flashcards, skill-building activities, quizzes, assignments, and videos—all within a single system.

The interactive ebook is organized across key thematic areas, addressing the historical context of Latinx and Chicano presence in the U.S., exploring ethnic identity development, and analyzing the impacts of socio-economic factors on these communities, including the intersection of race, religion, and resistance to discrimination. By exploring the constructs of machismo, marianismo, and the division of labor, the work offers insights into the cultural dynamics and the resilience of Latinx and Chicano populations amid adversities such as stereotypes, marginalization, and systemic challenges in education and labor.

 The Psychological Perspectives of Latinx and Chicano Populations is ideal for courses that focus on social sciences, ethnic studies, and community development.', 76.99, 'https://i.ibb.co/WvtDDVNH/IMG-4764.jpg', 'Textbook', true, '2026-05-03T18:13:20.897421+00:00', '2026-05-03T18:29:19.666163+00:00', 'physical', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, description, price, image_url, category, is_published, created_at, updated_at, book_format, file_url) VALUES ('f62fbdb3-ec96-4fcb-adb1-a7eb6f2bb87b', 'Developmental Psychology: Applications Across the Lifespan', 'Human Development and Family Science', 75, 'https://i.ibb.co/MxMM3qRB/IMG-4219.jpg', 'Human Development', true, '2026-05-03T18:35:44.883608+00:00', '2026-05-03T18:40:27.856266+00:00', 'physical', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, description, price, image_url, category, is_published, created_at, updated_at, book_format, file_url) VALUES ('46ab55f5-b175-4d0f-bece-8efc3a3101bf', 'An Examination of the Educational Trajectory of Foster Care Alumni Regarding the Social Capital Held by Their Foster Parents', 'Research indicates that the child in foster care has a volatile educational trajectory. This research study explains why and how to correct it', 225, 'https://i.ibb.co/4nM6S6rg/image-6487327.jpg', 'Research Study', true, '2026-05-04T21:02:59.687025+00:00', '2026-05-04T21:02:59.687025+00:00', 'pdf', 'https://grbogggykofvibexcxjz.supabase.co/storage/v1/object/public/book-files/1777928350290-cqyh0zvpla.pdf') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, description, price, image_url, category, is_published, created_at, updated_at, book_format, file_url) VALUES ('42109df1-b1c5-4f82-b50d-983759618a65', 'Broadening Our Multicultural Lens', 'Dr. Lundy’s indelible and proliferative mark in the field of psychology has greatly influenced my growth as a future physician. Her teachings expanded the understanding of my own intersectionality, contributing to my strong foundation of cultural competence as a member of the LGBT+ community and as a person of Armenian descent. Prior to encountering her work, I was battling a challenging academic period in my life and still developing my own multicultural lens as a member of a minority myself. In none of my years of education thus far as a young adult had I learned about the true psychology of resilience and self-agency, which imparted a strong impact on my life. It allowed me to understand my own lived experiences in relation to the vast patchwork of cultures in our world. The text is important for all undergraduate students during this critical period of neurodevelopment during young adulthood.

Perhaps the most outstanding quality of Dr. Lundy’s work that equips it for countless uses in the academic setting for students of all cultures and ethnicities is her invitation to apply its concepts to one’s own lived experiences. This is a process of growth that may not be timely, but the text is undoubtedly a warm and compassionate companion along this journey for the student. While exploring how children learn bias, stereotyping, and prejudice from the home, the work illuminates and identifies the opportunity for the student to reform a potentially inaccurate or hurtful belief into a sound one. From the lens of a neuroscience graduate, it’s clear that our ability to reform beliefs (namely rooted in neuroplasticity) remains ingrained in our brains into adulthood, well beyond our formative years.

Expanding on earlier thoughts, this text is arguably essential to all undergraduate students, regardless of major or focus of study, because it holds the direct power to change the ways in which we interact with each other while allowing us to understand each other’s differences instead of shying away from them. This journey allows each of us to recognize the various manifestations of racial and cultural disparities present in our world, examine them, and work towards eliminating them.

– Alexander Pate

University of Rhode Island, ’24 B.S., B.A.

Tufts University School of Medicine, Masters of Biological Sciences ‘26', 75, 'https://i.ibb.co/5W7fF1vJ/IMG-4763.jpg', 'Multicultural Psychology', true, '2026-05-03T18:16:30.162051+00:00', '2026-07-02T21:25:19.540981+00:00', 'physical', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, description, price, image_url, category, is_published, created_at, updated_at, book_format, file_url) VALUES ('d00fbfac-51ec-4dd8-971e-1f40f9cecb2c', 'So You''re On Your Own: A Practical Guide to Life Beyond Foster Care', 'This book was created with love, urgency, and the fierce belief that young people leaving state care deserve better and, specifically, more preparation. Each chapter is a conversation, a roadmap, a hug, an opportunity to be in community. You deserve tools, clarity, and the power to define and begin your own life. I hope this book helps you claim it. I wrote this book for the young person experiencing emerging adulthood - maybe a little anxious, maybe a little weathered, carrying more than most people will ever understand, while wondering how you will make it.', 16.99, 'https://i.ibb.co/tw75NgfC/IMG-4766.jpg', 'Young Adult Guidance', true, '2026-07-02T21:31:42.723929+00:00', '2026-07-03T19:22:31.517851+00:00', 'physical', NULL) ON CONFLICT DO NOTHING;

