-- Data for blogs (4 rows)
INSERT INTO public.blogs (id, title, content, excerpt, image_url, author, is_published, published_at, created_at, updated_at) VALUES ('1fa4da13-2ddc-4dac-891e-f800bcda3ce2', 'Breaking Barriers in Education Equity', '<h2>The Power of Inclusive Education</h2><p>Education equity isn''t just a buzzword—it''s a fundamental right. When we examine the disparities in educational access across communities, we find that the solutions often begin with individual educators who dare to challenge the status quo.</p><p>In my years of research and teaching, I''ve observed that the most impactful change happens when institutions commit to understanding the lived experiences of their students. This means going beyond textbook diversity and embracing a pedagogy that centers the voices of underrepresented communities.</p><h3>Key Strategies for Educators</h3><p>First, we must acknowledge that every student brings a unique perspective shaped by their background. Second, curriculum design should reflect the diversity of human experience. Third, assessment methods should be culturally responsive and equitable.</p><p>The journey toward true equity in education is long, but every step matters. Together, we can build learning environments where every student feels seen, heard, and valued.</p>', 'Exploring how systemic change begins in the classroom and extends to communities.', 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?w=400', 'Dr. Dina Lundy', true, '2026-03-14T13:30:33.709827+00:00', '2026-03-14T13:30:33.709827+00:00', '2026-03-14T13:30:33.709827+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.blogs (id, title, content, excerpt, image_url, author, is_published, published_at, created_at, updated_at) VALUES ('e5014af5-950e-441a-be7f-024869dbd0ac', 'Why Angela Olivia Burton is the best choice for ACS Commissioner', '<p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">It&nbsp;is&nbsp;a&nbsp;historical&nbsp;time&nbsp;for&nbsp;our&nbsp;city.&nbsp;Mayor&nbsp;Zohran&nbsp;Mamdani&nbsp;has&nbsp;not&nbsp;chosen&nbsp;heads&nbsp;of&nbsp;departments&nbsp;as&nbsp;his&nbsp;predecessors&nbsp;did.&nbsp;Indeed,&nbsp;a&nbsp;New&nbsp;Yorker&nbsp;with&nbsp;a&nbsp;justice-affected&nbsp;history&nbsp;has&nbsp;been&nbsp;appointed&nbsp;as&nbsp;the&nbsp;new&nbsp;commissioner&nbsp;of&nbsp;the&nbsp;Department&nbsp;of&nbsp;Corrections.&nbsp;Stanley&nbsp;Richards,&nbsp;a&nbsp;formerly&nbsp;incarcerated&nbsp;criminal&nbsp;justice&nbsp;reform&nbsp;advocate,&nbsp;earned&nbsp;an&nbsp;historic&nbsp;appointment&nbsp;as&nbsp;the&nbsp;first&nbsp;person&nbsp;to&nbsp;lead&nbsp;the&nbsp;city’s&nbsp;jail&nbsp;system&nbsp;who&nbsp;has&nbsp;previously&nbsp;served&nbsp;time&nbsp;in&nbsp;it.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">The&nbsp;New&nbsp;York&nbsp;City&nbsp;Administration&nbsp;of&nbsp;Children’s&nbsp;Services&nbsp;(ACS)&nbsp;will&nbsp;require&nbsp;a&nbsp;professional&nbsp;with&nbsp;similar&nbsp;foundational&nbsp;insight&nbsp;if&nbsp;NYC’s&nbsp;families&nbsp;are&nbsp;to&nbsp;receive&nbsp;the&nbsp;support&nbsp;they&nbsp;deserve&nbsp;and&nbsp;require.&nbsp;New&nbsp;York&nbsp;City&nbsp;had&nbsp;fallen&nbsp;under&nbsp;federal&nbsp;monitoring&nbsp;beginning&nbsp;in&nbsp;2015&nbsp;as&nbsp;a&nbsp;consequence&nbsp;of&nbsp;the&nbsp;disproportionate&nbsp;policing&nbsp;of&nbsp;poor&nbsp;Black&nbsp;and&nbsp;Brown&nbsp;families.&nbsp;In&nbsp;May&nbsp;2024,&nbsp;the&nbsp;New&nbsp;York&nbsp;Advisory&nbsp;Committee&nbsp;to&nbsp;the&nbsp;United&nbsp;States&nbsp;Commission&nbsp;on&nbsp;Civil&nbsp;Rights&nbsp;issued&nbsp;a&nbsp;report&nbsp;finding&nbsp;that&nbsp;“racism&nbsp;…&nbsp;continues&nbsp;to&nbsp;impact&nbsp;New&nbsp;York’s&nbsp;child&nbsp;welfare&nbsp;system&nbsp;and&nbsp;forms&nbsp;the&nbsp;foundation&nbsp;for&nbsp;how&nbsp;it&nbsp;functions.”</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">It&nbsp;is&nbsp;against&nbsp;the&nbsp;backdrop&nbsp;of&nbsp;chattel&nbsp;slavery&nbsp;and&nbsp;the&nbsp;prevailing&nbsp;wealth&nbsp;gap&nbsp;that&nbsp;Brown&nbsp;and&nbsp;Black&nbsp;families&nbsp;fail&nbsp;to&nbsp;escape&nbsp;poverty.&nbsp;These&nbsp;families&nbsp;are&nbsp;policed&nbsp;regarding&nbsp;their&nbsp;inability&nbsp;to&nbsp;pick&nbsp;themselves&nbsp;up&nbsp;by&nbsp;their&nbsp;bootstraps.&nbsp;Further,&nbsp;Investigators&nbsp;who&nbsp;investigate&nbsp;the&nbsp;poor&nbsp;lack&nbsp;cultural&nbsp;understanding&nbsp;within&nbsp;the&nbsp;paradigm&nbsp;of&nbsp;poverty&nbsp;and&nbsp;render&nbsp;damaging&nbsp;decisions&nbsp;that&nbsp;destroy&nbsp;families,&nbsp;children,&nbsp;as&nbsp;well&nbsp;as&nbsp;communities.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">There&nbsp;is&nbsp;a&nbsp;shortage&nbsp;of&nbsp;qualified&nbsp;foster&nbsp;homes.&nbsp;An&nbsp;investigation&nbsp;in&nbsp;2001&nbsp;indicated&nbsp;that&nbsp;one-sixth&nbsp;of&nbsp;resource&nbsp;homes&nbsp;fail&nbsp;to&nbsp;pass&nbsp;prerequisite&nbsp;determinants&nbsp;of&nbsp;adequacy.&nbsp;There&nbsp;is&nbsp;also&nbsp;a&nbsp;documented&nbsp;foster&nbsp;care&nbsp;to&nbsp;prison&nbsp;pipeline,&nbsp;a&nbsp;foster&nbsp;care&nbsp;to&nbsp;homelessness&nbsp;pipeline,&nbsp;and&nbsp;a&nbsp;foster&nbsp;care&nbsp;to&nbsp;mental&nbsp;illness&nbsp;pipeline.&nbsp;If&nbsp;the&nbsp;ACS&nbsp;were&nbsp;evaluated&nbsp;as&nbsp;a&nbsp;business,&nbsp;it&nbsp;would&nbsp;be&nbsp;classified&nbsp;as&nbsp;an&nbsp;abject&nbsp;failure&nbsp;lacking&nbsp;meaningful&nbsp;positive&nbsp;statistical&nbsp;outcomes.</span></p><p></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">In&nbsp;addition,&nbsp;a&nbsp;civil&nbsp;rights&nbsp;lawsuit&nbsp;filed&nbsp;in&nbsp;2024&nbsp;challenged&nbsp;the&nbsp;ACS&nbsp;use&nbsp;of&nbsp;“coercive&nbsp;tactics”&nbsp;for&nbsp;warrantless&nbsp;home&nbsp;searches,&nbsp;arguing&nbsp;these&nbsp;practices&nbsp;violate&nbsp;the&nbsp;constitutional&nbsp;rights&nbsp;of&nbsp;families,&nbsp;with&nbsp;a&nbsp;disproportionate&nbsp;impact&nbsp;on&nbsp;Black&nbsp;and&nbsp;Hispanic&nbsp;families.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">Angela&nbsp;Olivia&nbsp;Burton&nbsp;has&nbsp;emerged&nbsp;as&nbsp;a&nbsp;finalist&nbsp;to&nbsp;lead&nbsp;the&nbsp;ACS,&nbsp;one&nbsp;of&nbsp;the&nbsp;largest&nbsp;and&nbsp;most-scrutinized&nbsp;child&nbsp;welfare&nbsp;systems&nbsp;in&nbsp;the&nbsp;country.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">Angela&nbsp;is&nbsp;not&nbsp;a&nbsp;bureaucratic&nbsp;insider.&nbsp;She&nbsp;is&nbsp;a&nbsp;public&nbsp;interest&nbsp;attorney,&nbsp;legal&nbsp;scholar,&nbsp;and&nbsp;long-time&nbsp;family&nbsp;defense&nbsp;advocate&nbsp;whose&nbsp;work&nbsp;has&nbsp;centered&nbsp;on&nbsp;constitutional&nbsp;family&nbsp;rights,&nbsp;racial&nbsp;equity,&nbsp;and&nbsp;systemic&nbsp;reform.&nbsp;Her&nbsp;career&nbsp;has&nbsp;included&nbsp;academic&nbsp;leadership&nbsp;roles&nbsp;at&nbsp;the&nbsp;City&nbsp;University&nbsp;of&nbsp;New&nbsp;York&nbsp;School&nbsp;of&nbsp;Law&nbsp;and&nbsp;clinical&nbsp;legal&nbsp;training&nbsp;in&nbsp;children’s&nbsp;rights&nbsp;and&nbsp;family&nbsp;law,&nbsp;as&nbsp;well&nbsp;as&nbsp;advocacy&nbsp;roles&nbsp;focused&nbsp;on&nbsp;reducing&nbsp;unnecessary&nbsp;child&nbsp;welfare&nbsp;investigations.&nbsp;She&nbsp;has&nbsp;been&nbsp;publicly&nbsp;associated&nbsp;with&nbsp;efforts&nbsp;to&nbsp;“narrow&nbsp;the&nbsp;front&nbsp;door”&nbsp;of&nbsp;the&nbsp;child&nbsp;welfare&nbsp;system&nbsp;—&nbsp;reducing&nbsp;surveillance&nbsp;and&nbsp;removals&nbsp;while&nbsp;increasing&nbsp;community-based&nbsp;supports.&nbsp;Supporters&nbsp;view&nbsp;her&nbsp;as&nbsp;a&nbsp;reformer&nbsp;committed&nbsp;to&nbsp;addressing&nbsp;racial&nbsp;disproportionality&nbsp;and&nbsp;due&nbsp;process&nbsp;concerns.&nbsp;Family&nbsp;preservation&nbsp;must&nbsp;be&nbsp;the&nbsp;goal.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">ACS&nbsp;is&nbsp;at&nbsp;the&nbsp;intersection&nbsp;of&nbsp;safety,&nbsp;poverty,&nbsp;race,&nbsp;and&nbsp;power.&nbsp;The&nbsp;next&nbsp;commissioner&nbsp;will&nbsp;shape&nbsp;how&nbsp;New&nbsp;York&nbsp;City&nbsp;repairs&nbsp;the&nbsp;inequity&nbsp;that&nbsp;policed&nbsp;families&nbsp;continue&nbsp;to&nbsp;face.&nbsp;Burton’s&nbsp;candidacy&nbsp;underscores&nbsp;a&nbsp;larger&nbsp;national&nbsp;debate:&nbsp;Is&nbsp;child&nbsp;welfare&nbsp;primarily&nbsp;an&nbsp;investigative&nbsp;apparatus,&nbsp;or&nbsp;should&nbsp;it&nbsp;reorient&nbsp;to&nbsp;a&nbsp;model&nbsp;grounded&nbsp;in&nbsp;family&nbsp;preservation&nbsp;rather&nbsp;than&nbsp;agency&nbsp;control?&nbsp;Indeed,&nbsp;very&nbsp;few&nbsp;families&nbsp;ever&nbsp;recover&nbsp;from&nbsp;the&nbsp;broken&nbsp;bonds&nbsp;severed&nbsp;by&nbsp;ACS&nbsp;and&nbsp;agencies&nbsp;like&nbsp;it.</span></p><p></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">Whatever&nbsp;one’s&nbsp;position,&nbsp;this&nbsp;appointment&nbsp;will&nbsp;not&nbsp;be&nbsp;symbolic.&nbsp;It&nbsp;will&nbsp;define&nbsp;our&nbsp;city’s&nbsp;humanity&nbsp;in&nbsp;a&nbsp;system&nbsp;that&nbsp;affects&nbsp;thousands&nbsp;of&nbsp;Black,&nbsp;Brown,&nbsp;and&nbsp;poor&nbsp;white&nbsp;children&nbsp;and&nbsp;families&nbsp;annually.&nbsp;Leadership&nbsp;know-how,&nbsp;cultural&nbsp;awareness,&nbsp;and&nbsp;legal&nbsp;prowess&nbsp;are&nbsp;what&nbsp;we&nbsp;need.&nbsp;As&nbsp;a&nbsp;New&nbsp;Yorker,&nbsp;I&nbsp;submit&nbsp;that&nbsp;Angela&nbsp;Burton&nbsp;has&nbsp;the&nbsp;skills,&nbsp;historical&nbsp;skin&nbsp;in&nbsp;the&nbsp;game,&nbsp;and&nbsp;documented&nbsp;understanding&nbsp;of&nbsp;what&nbsp;New&nbsp;York&nbsp;City&nbsp;families&nbsp;under&nbsp;court&nbsp;purview&nbsp;endure.</span></p><p><span style="background-color: rgb(255, 255, 255); color: rgb(17, 17, 17);">Dr.&nbsp;Adina&nbsp;Lundy&nbsp;is&nbsp;a&nbsp;native&nbsp;of&nbsp;Brownsville&nbsp;Brooklyn&nbsp;and&nbsp;associate&nbsp;director&nbsp;of&nbsp;undergraduate&nbsp;psychology&nbsp;at&nbsp;the&nbsp;University&nbsp;of&nbsp;Rhode&nbsp;Island.&nbsp;She&nbsp;also&nbsp;serves&nbsp;as&nbsp;an&nbsp;expert&nbsp;witness&nbsp;for&nbsp;the&nbsp;Office&nbsp;of&nbsp;the&nbsp;Public&nbsp;Defender,&nbsp;Family&nbsp;Court&nbsp;of&nbsp;Passaic&nbsp;County,&nbsp;N.J.</span></p><p></p>', 'It is a historical time for our city. Mayor Zohran Mamdani has not chosen heads of departments as his predecessors did. Indeed, a New Yorker with a justice-affected history has been appointed as the new commissioner of the Department of Corrections. Stanley Richards, a formerly incarcerated criminal justice reform advocate, earned an historic appointment as the first person to lead the city’s jail system who has previously served time in it.', 'https://i0.wp.com/amsterdamnews.com/wp-content/uploads/2026/03/o12-op-ed.2-scaled.jpg?resize=2000%2C1333&ssl=1', 'Dr. Dina Lundy', true, '2026-03-14T10:56:37.983+00:00', '2026-03-14T10:56:38.279203+00:00', '2026-03-14T16:57:34.025114+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.blogs (id, title, content, excerpt, image_url, author, is_published, published_at, created_at, updated_at) VALUES ('a8fe0832-09ee-41d3-bec1-82228e9e622a', 'If You Don''t Know About Dr. Victoria Copeland''s Work, I Have a Lot to Share', '<p><span style="color: rgba(0, 0, 0, 0.9);">Dr.&nbsp;Victoria&nbsp;Copeland&nbsp;has&nbsp;fundamentally&nbsp;shifted&nbsp;how&nbsp;many&nbsp;of&nbsp;us&nbsp;understand&nbsp;what&nbsp;is&nbsp;commonly&nbsp;referred&nbsp;to&nbsp;as&nbsp;the&nbsp;“child&nbsp;welfare&nbsp;system.”&nbsp;I,&nbsp;myself,&nbsp;learned&nbsp;this&nbsp;yesterday&nbsp;at&nbsp;Joyce&nbsp;McMillan&#39;s&nbsp;panel&nbsp;&quot;&nbsp;Supporting&nbsp;Families&nbsp;Without&nbsp;Surveillance&quot;.</span></p><p><span style="color: rgba(0, 0, 0, 0.9);">A&nbsp;scholar&nbsp;who&nbsp;emerged&nbsp;from&nbsp;the&nbsp;University&nbsp;of&nbsp;California,&nbsp;Los&nbsp;Angeles,&nbsp;Copeland&nbsp;is&nbsp;widely&nbsp;recognized&nbsp;for&nbsp;coining&nbsp;the&nbsp;term&nbsp;</span><strong style="color: rgba(0, 0, 0, 0.9);">“family&nbsp;policing&nbsp;system”</strong><span style="color: rgba(0, 0, 0, 0.9);">—a&nbsp;reframing&nbsp;that&nbsp;challenges&nbsp;us&nbsp;to&nbsp;interrogate&nbsp;the&nbsp;role&nbsp;of&nbsp;surveillance,&nbsp;control,&nbsp;and&nbsp;punishment&nbsp;embedded&nbsp;within&nbsp;systems&nbsp;that&nbsp;are&nbsp;often&nbsp;positioned&nbsp;as&nbsp;protective&nbsp;but&nbsp;directed&nbsp;at&nbsp;Blacks.&nbsp;If&nbsp;you&#39;re&nbsp;a&nbsp;critical&nbsp;thinker&nbsp;it&nbsp;is&nbsp;possible&nbsp;for&nbsp;you&nbsp;to&nbsp;recognize&nbsp;that&nbsp;this&nbsp;country&nbsp;would&nbsp;seek&nbsp;to&nbsp;help&nbsp;or&nbsp;protect&nbsp;my&nbsp;community.</span></p><p><span style="color: rgba(0, 0, 0, 0.9);">&nbsp;Dr.&nbsp;Copeland&nbsp;provided&nbsp;the&nbsp;terminology&nbsp;for&nbsp;what&nbsp;we&nbsp;were&nbsp;experiencing,&nbsp;watching,&nbsp;or,&nbsp;indeed,&nbsp;(if&nbsp;you&nbsp;are&nbsp;a&nbsp;child&nbsp;social&nbsp;worker)&nbsp;performing.&nbsp;She&nbsp;described&nbsp;your&nbsp;job&nbsp;for&nbsp;you...You&nbsp;had&nbsp;always&nbsp;been&nbsp;viewed&nbsp;as&nbsp;the&nbsp;police..&nbsp;by&nbsp;us...but&nbsp;now,&nbsp;we,&nbsp;the&nbsp;targets,&nbsp;had&nbsp;a&nbsp;description&nbsp;that&nbsp;fit,&nbsp;thanks&nbsp;to&nbsp;Dr.&nbsp;Victoria&nbsp;Copeland.</span></p><p><span style="color: rgba(0, 0, 0, 0.9);">Her&nbsp;pioneering&nbsp;work&nbsp;situates&nbsp;child&nbsp;welfare&nbsp;within&nbsp;a&nbsp;broader&nbsp;</span><strong style="color: rgba(0, 0, 0, 0.9);">carceral&nbsp;ecosystem</strong><span style="color: rgba(0, 0, 0, 0.9);">,&nbsp;arguing&nbsp;that&nbsp;interventions,&nbsp;disguised&nbsp;as&nbsp;</span><em style="color: rgba(0, 0, 0, 0.9);">HELP</em><span style="color: rgba(0, 0, 0, 0.9);">&nbsp;disproportionately,&nbsp;</span><strong style="color: rgba(0, 0, 0, 0.9);">negatively,</strong><span style="color: rgba(0, 0, 0, 0.9);">&nbsp;impact&nbsp;Black&nbsp;families&nbsp;and&nbsp;function&nbsp;as&nbsp;mechanisms&nbsp;of&nbsp;monitoring,&nbsp;regulation,&nbsp;control,&nbsp;and&nbsp;monetization..&nbsp;rather&nbsp;than&nbsp;support&nbsp;or,&nbsp;indeed,&nbsp;</span><em style="color: rgba(0, 0, 0, 0.9);">HELP.</em></p><p><span style="color: rgba(0, 0, 0, 0.9);">What&nbsp;makes&nbsp;Copeland’s&nbsp;scholarship&nbsp;especially&nbsp;powerful&nbsp;is&nbsp;that&nbsp;it&nbsp;is&nbsp;not&nbsp;abstract—it&nbsp;is&nbsp;grounded&nbsp;in:</span></p><p></p><ul><li><span style="color: var(--color-text);">Lived&nbsp;realities&nbsp;of&nbsp;system-impacted&nbsp;families</span></li><li><span style="color: var(--color-text);">Black&nbsp;feminist&nbsp;theory&nbsp;and&nbsp;abolitionist&nbsp;praxis</span></li><li><span style="color: var(--color-text);">Critical&nbsp;analysis&nbsp;of&nbsp;data,&nbsp;surveillance,&nbsp;and&nbsp;decision-making&nbsp;systems</span></li></ul><p></p><p><span style="color: rgba(0, 0, 0, 0.9);">She&nbsp;centers&nbsp;the&nbsp;harder&nbsp;questions,&nbsp;the&nbsp;ones&nbsp;that&nbsp;require&nbsp;you&nbsp;to&nbsp;look&nbsp;at&nbsp;your&nbsp;inner&nbsp;racist:</span></p><p></p><ul><li><span style="color: var(--color-text);">Who&nbsp;is&nbsp;being&nbsp;protected—and&nbsp;from&nbsp;whom?</span></li><li><span style="color: var(--color-text);">What&nbsp;does&nbsp;“safety”&nbsp;actually&nbsp;mean&nbsp;in&nbsp;practice?</span></li><li><span style="color: var(--color-text);">And&nbsp;how&nbsp;might&nbsp;systems&nbsp;of&nbsp;care&nbsp;be&nbsp;reimagined&nbsp;outside&nbsp;of&nbsp;punishment&nbsp;and&nbsp;surveillance?</span></li></ul><p></p><p><span style="color: rgba(0, 0, 0, 0.9);">For&nbsp;those&nbsp;of&nbsp;us&nbsp;working&nbsp;in&nbsp;child&nbsp;welfare,&nbsp;juvenile&nbsp;justice,&nbsp;education,&nbsp;or&nbsp;policy—her&nbsp;work&nbsp;is&nbsp;not&nbsp;optional&nbsp;reading.&nbsp;It&nbsp;is&nbsp;essential.&nbsp;As&nbsp;such,&nbsp;I&nbsp;am&nbsp;linking&nbsp;this&nbsp;scholar&#39;s&nbsp;google&nbsp;scholar&nbsp;page&nbsp;here:&nbsp;</span><a href="https://scholar.google.com/scholar?start=10&amp;q=victoria+copeland+child+welfare&amp;hl=en&amp;as_sdt=0,40" rel="noopener noreferrer" target="_blank" style="color: var(--color-text-link-visited); background-color: var(--artdeco-reset-link-background-color-transparent);">https://scholar.google.com/scholar?start=10&amp;q=victoria+copeland+child+welfare&amp;hl=en&amp;as_sdt=0,40</a></p><p><strong style="color: rgba(0, 0, 0, 0.9);"><em>Even&nbsp;more&nbsp;compelling&nbsp;is&nbsp;that&nbsp;Copeland&nbsp;has&nbsp;continued&nbsp;producing&nbsp;scholarship&nbsp;under&nbsp;extraordinary&nbsp;personal&nbsp;health&nbsp;challenges,&nbsp;underscoring&nbsp;both&nbsp;her&nbsp;commitment&nbsp;and&nbsp;the&nbsp;structural&nbsp;inequities&nbsp;scholars&nbsp;often&nbsp;navigate.&nbsp;I&nbsp;encourage&nbsp;you&nbsp;to&nbsp;support&nbsp;Dr.&nbsp;Copeland,&nbsp;monetarily,&nbsp;by&nbsp;sharing&nbsp;her&nbsp;story,&nbsp;by&nbsp;sharing&nbsp;this&nbsp;post,&nbsp;and&nbsp;looking&nbsp;inward.</em></strong></p><h3><span style="color: rgba(0, 0, 0, 0.9);">🔗&nbsp;Her&nbsp;GoFundMe</span></h3><p></p><ul><li><a href="https://www.gofundme.com/f/help-vs-medical-expenses?utm_source=chatgpt.com" rel="noopener noreferrer" target="_blank" style="color: var(--color-text-link-visited); background-color: var(--artdeco-reset-link-background-color-transparent);">Support&nbsp;Victoria’s&nbsp;medical&nbsp;care</a></li></ul><p></p><p><span style="color: rgba(0, 0, 0, 0.9);">This&nbsp;fundraiser&nbsp;supports&nbsp;Dr.&nbsp;Victoria&nbsp;Copeland&#39;s&nbsp;ongoing&nbsp;medical&nbsp;needs&nbsp;related&nbsp;to&nbsp;multiple&nbsp;serious&nbsp;chronic&nbsp;conditions,&nbsp;including&nbsp;Ehlers-Danlos&nbsp;syndrome,&nbsp;dysautonomia,&nbsp;and&nbsp;Long&nbsp;COVID,&nbsp;which&nbsp;have&nbsp;significantly&nbsp;impacted&nbsp;her&nbsp;daily&nbsp;functioning.</span></p><p><span style="color: rgba(0, 0, 0, 0.9);">#ChildWelfare&nbsp;#FamilyPolicing&nbsp;#JuvenileJustice&nbsp;#Equity&nbsp;#AbolitionistFrameworks&nbsp;#BlackFeministThought&nbsp;#SystemsChange&nbsp;#DinaLundyAuthor</span></p><p></p>', 'Who Coined the term Family Policing?', 'https://i.ibb.co/hJKbrmTw/IMG-4561.jpg', 'Dr. Dina Lundy', true, '2026-03-29T00:34:01.656+00:00', '2026-03-29T00:34:01.907861+00:00', '2026-03-29T00:35:35.348698+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.blogs (id, title, content, excerpt, image_url, author, is_published, published_at, created_at, updated_at) VALUES ('b7c999ce-c16d-4a4d-b3f7-18fd2a2259e9', 'Who Coined the Term Family Policing', 'Who Coined the Term Family Policing', 'Who Coined the Term Family Policing', 'https://i.ibb.co/hJKbrmTw/IMG-4561.jpg', 'Dina Lundy', false, NULL, '2026-03-29T00:35:11.845589+00:00', '2026-03-29T00:36:53.90623+00:00') ON CONFLICT DO NOTHING;

