INSERT INTO public.newsletters (id, title, content, image1_url, image2_url, image3_url, is_published, published_at, created_at, updated_at) VALUES ('7a2dcd08-8df5-4a20-ad90-b7fbc61dd4f4', 'Spring 2026 Newsletter', '<h2>A Season of Growth</h2><p>Dear friends and colleagues, as we enter spring, I''m thrilled to share some exciting updates from our community.</p><p>This quarter, we launched our new mentorship program connecting foster youth with professional mentors across the tri-state area. The response has been overwhelming, with over 50 mentor-mentee pairs already matched.</p><h3>Upcoming Events</h3><p>Mark your calendars for our Annual Education Equity Summit on June 15th in New York City. Early bird registration is now open!</p><p>Warm regards,<br/>Dr. Dina Lundy</p>', 'https://images.unsplash.com/photo-1456513080510-7bf3a84b82f8?w=400', NULL, NULL, true, '2026-03-14T13:30:33.709827+00:00', '2026-03-14T13:30:33.709827+00:00', '2026-03-14T13:30:33.709827+00:00') ON CONFLICT DO NOTHING;

-- Data for podcasts (2 rows)
INSERT INTO public.podcasts (id, title, description, audio_url, episode_number, duration, image_url, is_published, published_at, created_at, updated_at, category, podcast_format, video_url) VALUES ('3541d276-90c3-49ae-a994-925cc17fdeee', 'Surviving Academe as a Person of Color', 'In this episode, Dr. Lundy discusses the intersection of cultural identity and academic achievement with guest educators from diverse backgrounds.', NULL, 1, '45 min', 'https://i.ibb.co/cSv972Wc/Your-paragraph-text-2.png', false, '2026-03-14T13:30:33.709827+00:00', '2026-03-14T13:30:33.709827+00:00', '2026-03-30T23:58:53.329625+00:00', 'The Law Professor', 'video', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.podcasts (id, title, description, audio_url, episode_number, duration, image_url, is_published, published_at, created_at, updated_at, category, podcast_format, video_url) VALUES ('7d9f9e21-79c0-4ead-a3fd-68a7d3c6dcec', 'From Foster Care to NYU LAW', NULL, NULL, 2, '29', 'https://i.ibb.co/DDMrVxLs/Banner-para-Linkedin-Licenciada-Marketing-Minimalista-Beige-2.png', true, NULL, '2026-04-27T00:40:48.632945+00:00', '2026-04-27T01:41:37.561402+00:00', 'Law School', 'video', 'https://youtu.be/D0-D1R2sPsY') ON CONFLICT DO NOTHING;

-- Data for publishing (5 rows)
INSERT INTO public.publishing (id, title, description, publication_type, url, image_url, published_date, is_published, created_at, updated_at, author, abstract) VALUES ('1ea8800d-4efe-4600-8ce4-261ebcabd537', 'The Long-Term Implications of Transracial Adoption and its Effect on Identity Development and Social Adaptation', 'Out Group Adoption', 'Transracial adoption, identity development, cultural socialization', 'https://papers.ssrn.com/sol3/papers.cfm?abstract_id=4877304', 'https://i.ibb.co/hJkNcHZK/Full-Size-Render.jpg', '2024-06-27', true, '2026-03-14T00:30:00.876822+00:00', '2026-03-17T01:42:16.616221+00:00', 'Adina Lundy , Dani Shifman', 'Transracial adoption refers to the process of adopting a child of one race or ethnicity into the home of a different race, ethnicity, or culture. The topic of transracial adoption has become increasingly prevailing in a globally speaking context as its popularity augments with time. This literature review aims to analyze further pre-existing research on the long-term impacts and effects of transracial adoption on identity development and social adaptation processes in transracial adoptees. This review takes note of important skills and practices to be learned, such as cultural socialization, and how said skills and practices positively correlate with identity development in transracially adopted individuals. This review examines the factors that inevitably influence an adoptee''s sense of identity, both racial and cultural, also including transracially adopting parental responsibilities and actions to provide proper exposure to the adoptee''s biological cultural heritage. Transracial adoptees may face various experiences of discrimination and microaggressions in our present, racially divided society. Thus, these experiences will be understood and handled better in the long term. Including the works of multiple different studies and findings, this review points out notable common themes and distinctive traits in the literature. Discussed are the outcomes for transracial adoptees in many aspects. Additionally, be sure to note the gap in the literature in terms of adequate research to draw solid conclusions. This literature review provides a comprehensive overview of the correlation between identity and adoption, highlights areas for potential further research, and offers ideas of integration to enhance the overall well-being of transracial adoptees further as they experience life.') ON CONFLICT DO NOTHING;
INSERT INTO public.publishing (id, title, description, publication_type, url, image_url, published_date, is_published, created_at, updated_at, author, abstract) VALUES ('11a26dfc-2b2c-4642-b780-d6cd86fefbf2', 'Exploring the Social Psychological Undercurrents of Workplace Racial Battle Fatigue (RBF) for Minority Faculty at Predominantly White Institutions (PWIs) in the U.S.', 'Published in the Journal of Educational Psychology, this study examines how implicit bias affects grading practices and student outcomes in university settings.', 'Journal Article', 'https://rais.education/wp-content/uploads/06200.pdf', 'https://images.unsplash.com/photo-1481627834876-b7833e8f5570?w=400', '2025-11-15', true, '2026-03-14T13:30:33.709827+00:00', '2026-03-17T01:44:05.527205+00:00', 'Dr. Dina Lundy', 'This phenomenological study explores the lived experiences of minority students in predominantly white institutions, revealing patterns of implicit bias that affect academic performance and retention rates. The findings suggest that targeted faculty training programs can significantly reduce bias-related disparities.') ON CONFLICT DO NOTHING;
INSERT INTO public.publishing (id, title, description, publication_type, url, image_url, published_date, is_published, created_at, updated_at, author, abstract) VALUES ('b9ab839f-0248-4b7d-a30d-aa5e0a59ed26', 'Why Angela Olivia Burton is the best choice for ACS Commish', NULL, 'Opinion Editorial', 'OP-ED: Why Angela Olivia Burton is the best choice for ACS Commish', 'https://i.ibb.co/9HksvLPD/IMG-4516.jpg', '2026-03-12', true, '2026-03-17T00:55:04.601862+00:00', '2026-03-17T01:19:26.125551+00:00', 'Dr. Dina Lundy ', 'Angela Olivia Burton has emerged as a finalist to lead the New York City Administration for Children''s Services (ACS), one of the largest and most scrutinized child welfare systems in the country.') ON CONFLICT DO NOTHING;
INSERT INTO public.publishing (id, title, description, publication_type, url, image_url, published_date, is_published, created_at, updated_at, author, abstract) VALUES ('6b316233-0229-4cf8-be09-e4884e12eaf7', 'Institutional Policy Dossier: The Psychological Toll of Academic Surveillance on Black Women Faculty A Policy Framework for Equity, Accountability, Faculty Retention, and Institutional Reform', NULL, 'White Paper', NULL, 'https://i.ibb.co/Nz2w5Vz/Screenshot-2026-05-24-at-8-56-00-PM.png', NULL, true, '2026-05-25T00:55:41.708407+00:00', '2026-05-25T00:56:57.443469+00:00', 'Adina Lundy', 'Black women faculty continue to experience disproportionate institutional surveillance, challenges to
pedagogical legitimacy, racialized scrutiny, and emotional exhaustion within higher education systems.
Despite increasing representation in colleges and universities, many continue to navigate academic
cultures that question their expertise, authority, and belonging. This institutional policy dossier
examines the relationship between racialized surveillance, professional weathering, performative
allyship, and organizational inequity in higher education. Drawing from Black feminist thought, Critical
Race Theory, and higher education research, the report argues that universities frequently engage in
symbolic diversity initiatives without implementing structural safeguards that meaningfully protect Black
women faculty. The dossier identifies recurring institutional patterns including heightened scrutiny of
teaching, student complaints rooted in implicit bias, unequal service burdens, isolation from leadership
pipelines, and the normalization of emotional labor. These institutional conditions contribute not only to
diminished professional satisfaction but also to measurable psychological and physiological
consequences. This report advances a comprehensive policy framework that includes: Equity
Accountability Dashboards Faculty Wellness and Retention Grants Restorative Equity Review Boards
Bias Audits in Faculty Evaluation Systems Protected Leadership Pipelines for Women of Color
Institutional Climate Transparency Measures The dossier concludes that higher education institutions
must move beyond symbolic diversity commitments toward measurable systems of accountability,
protection, and structural transformation.') ON CONFLICT DO NOTHING;
INSERT INTO public.publishing (id, title, description, publication_type, url, image_url, published_date, is_published, created_at, updated_at, author, abstract) VALUES ('64958410-e90a-4e17-b002-10bde6ff7991', 'The Cyberpsychological Dimensions of Healthcare Cybersecurity Crime Risks', NULL, 'Book chapter', 'https://www.igi-global.com/chapter/the-cyberpsychological-dimensions-of-healthcare-cybersecurity-crime-risks/402890', 'https://i.ibb.co/TDVcQnvj/IMG-4916.avif', '2026-04-14', true, '2026-04-28T10:08:41.019829+00:00', '2026-05-26T21:32:31.142613+00:00', 'Adina Lundy (University of Rhode Island, USA), Darrell Norman Burrell (Marymount University, USA & Pellegrino Center for Clinical Bioethics, Georgetown University, USA), and Allison Huff (College of Medicine-Tucson, University of Arizona, USA)', 'This study examines the cyberpsychological dimensions of cybersecurity risks in healthcare, emphasizing how human cognition, emotion, and organizational culture shape vulnerability within digitally transformed care environments. As healthcare integrates electronic health records, AI diagnostics, and telehealth systems, leaders, often trained in clinical or administrative domains, remain largely untrained in human factors psychology, limiting their capacity to address behavioral risk. Cyberattacks increasingly exploit cognitive biases such as urgency, authority, and trust, while clinicians under high cognitive load and ethical pressure frequently bypass protocols perceived as obstructive to patient care. Through an integrative, evidence-based framework grounded in cyberpsychological theory, this research aims to align technical controls with user behavior, leadership awareness, and institutional culture. The goal is to transition healthcare cybersecurity from a reactive, technology-centric model to a proactive, human-centered paradigm that fosters resilience, ethical responsibility, and trust across clinical and digital ecosystems.') ON CONFLICT DO NOTHING;

