-- Data for tedx_talks (2 rows)
INSERT INTO public.tedx_talks (id, title, author, video_url, thumbnail_url, description, is_published, created_at, updated_at) VALUES ('fb82af2a-e853-4015-ac9a-60b6bccba1a4', 'Hope from the Edge | Adina Lundy | TEDxURI', 'Dr. Dina Lundy', 'https://www.youtube.com/watch?v=M9AIcz8mHU0&t=118s', NULL, 'Adina talks about her grief while she took care of her mom, who was suffering from Alzheimer’s.  As a method of coping with her troubles at home, she decided to engage in meaningful activity that was bigger than herself.  Adina found comfort by volunteering to help children in foster care who did not have the luxury of feeling safe during their childhood.  She observed that these children persevered through circumstances that were out of their control.  Their resilience gave her hope in her personal time of despair as she coped with her mom’s illness. Adrina Lundy is from Brownsville, Brooklyn. She earned a Master’s in Developmental Psychology from Harvard and is a lecturer here at the University of Rhode Island where she teaches human development, women and psychology, and multicultural psychology. Her research intersects at college degree completion for demographics underrepresented in higher education, the ways in which social capital is tethered to that effort, and, the criminalization of poverty vis a vis the foster care removal paradigm. As a restaurateur, after earning the baccalaureate, she provided employment, exclusively, to felons returning home. This talk was given at a TEDx event using the TED conference format but independently organized by a local community.', true, '2026-03-24T21:31:00.101982+00:00', '2026-03-24T21:31:00.101982+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.tedx_talks (id, title, author, video_url, thumbnail_url, description, is_published, created_at, updated_at) VALUES ('81a8fe82-1a19-44da-86ac-425e5b946026', ' 6,539 Black people tried to become police officers on Long Island. Only 67 were hired.', 'Dr. Dina Lundy', 'https://youtu.be/YVQwL6mI0AE?si=J3ih292a9225S19l', 'https://i.ibb.co/sd83sjYR/IMG-4582.jpg', 'A Newsday analysis found that minorities who took Nassau and Suffolk police department tests had harder paths to being hired', false, '2026-03-29T20:30:31.356038+00:00', '2026-04-28T10:10:06.956821+00:00') ON CONFLICT DO NOTHING;

-- Data for philanthropy_cards (2 rows)
INSERT INTO public.philanthropy_cards (id, title, description, image_url, link_url, sort_order, is_published, created_at, updated_at) VALUES ('cb53caea-25e6-4967-acf0-3df4a220b872', 'Multicultural Psychology Syllabus:  Introduction to Multicultural Psychology', 'In this course, we will focus on differences in worldviews, differences in
communication, issues of racism, racial/cultural identity development, and immigration. The resources of this course were chosen to tether psychology to culture. Culture is a critical factor in the way human beings think, feel, act, and interact. It is my hope that you will gain a better understanding of the ways in which sociocultural and ethnopolitical contexts influence psychological processes, learn about empirical methods in multicultural psychology, and achieve better appreciation of cultural groups within and outside of the United States. This course is an introduction to multicultural psychology theory, research, and practice. It aims to develop students’ multicultural competence (i.e., knowledge, awareness, and skills) in order to prepare them to live, cultivate relationships and work with individuals from diverse socio-cultural backgrounds. I aim to increase students’ understanding of, and commitment to, social justice in their personal and professional lives. Topics covered include: ability, age, ethnicity,gender, nationality, race, religion, sex, sexual orientation, spirituality, socioeconomic status,injustice and other issues of diversity in ours and global society; intersectionality; socialization;various forms of privilege and oppression; intergroup conflict and communication; and advocacy. These topics will be addressed as they relate to multiculturally competent and ethical education, research, clinical practice, and advocacy work in psychology (and allied fields).
', 'https://i.ibb.co/Swnwqhbv/Screenshot-2026-03-14-190950.png', 'https://docs.google.com/document/d/12uXPytfRayxYDrI2uktWb98_leZLe9GqUK4PsY-j3Ds/edit?tab=t.0', 1, false, '2026-03-14T13:10:20.072591+00:00', '2026-03-30T23:01:52.055934+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.philanthropy_cards (id, title, description, image_url, link_url, sort_order, is_published, created_at, updated_at) VALUES ('1b3ae16e-477a-49eb-ac5b-6e862be3b75f', 'Foster Youth Mentorship Program', 'Connecting former foster youth with professional mentors to provide guidance, support, and career development opportunities for a brighter future.', 'https://images.unsplash.com/photo-1529390079861-591de354faf5?w=400', 'https://example.com/mentorship', 1, false, '2026-03-14T13:30:33.709827+00:00', '2026-03-30T23:01:59.627945+00:00') ON CONFLICT DO NOTHING;

